const fs = require('fs');
let src = fs.readFileSync('lib/main.dart', 'utf8');
let count = 0;
function replace(find, rep, label) {
  if (!src.includes(find)) { console.error('NOT FOUND: ' + label); process.exit(1); }
  src = src.replace(find, rep);
  count++;
  console.log('OK: ' + label);
}

